import React from 'react';
import { CheckIcon, XIcon, MailIcon, Building2Icon } from 'lucide-react';

const RiyalIcon = "data:image/png;base64,";

const CONTACT_EMAIL = 'basira.noreply@gmail.com';

const plans = [
    { name: 'مجاني', price: '0', period: 'للتجربة',
      features: [
        { text: 'عقد واحد / شهر', included: true },
        { text: '3 أسئلة لكل عقد', included: true },
        { text: 'التحليل الأساسي', included: true },
        { text: 'إنشاء العقود', included: false },
      ],
      cta: null,
    },
    { name: 'أساسي', price: '29', period: '/ شهر', badge: 'الأكثر طلبًا', highlighted: true,
      features: [
        { text: '10 عقود / شهر', included: true },
        { text: 'أسئلة غير محدودة', included: true },
        { text: 'حفظ التقارير وسجل التحليل', included: true },
        { text: 'إنشاء العقود', included: false },
      ],
      cta: `mailto:${CONTACT_EMAIL}?subject=طلب اشتراك أساسي - بصيرة`,
    },
    { name: 'احترافي', price: '59', period: '/ شهر', badge: 'أفضل قيمة', highlighted: false,
      features: [
        { text: '30 عقد / شهر', included: true },
        { text: 'أسئلة غير محدودة', included: true },
        { text: 'إنشاء 5 عقود / شهر', included: true },
        { text: 'أولوية في الدعم', included: true },
      ],
      cta: `mailto:${CONTACT_EMAIL}?subject=طلب اشتراك احترافي - بصيرة`,
    },
    { name: 'ادفع بقدر ما تستخدم', price: '5', period: '/ عقد', badge: '', highlighted: false,
      features: [
        { text: 'بدون اشتراك شهري', included: true },
        { text: 'ادفع فقط عند الحاجة', included: true },
        { text: 'أسئلة غير محدودة للعقد', included: true },
        { text: 'إنشاء العقود', included: false },
      ],
      cta: `mailto:${CONTACT_EMAIL}?subject=طلب اشتراك - ادفع بقدر ما تستخدم - بصيرة`,
    },
];

export function PricingSection() {
    return (
        <section id="pricing" className="py-24 bg-eclipse" dir="rtl">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="text-center mb-14">
                    <h2 className="text-4xl font-extrabold font-heading text-cream mb-4">الأسعار والباقات</h2>
                    <p className="text-center text-cream-dim max-w-2xl mx-auto mb-10 text-lg leading-8">
                        باقات مرنة تناسب الأفراد والشركات. يمكنك الاشتراك حاليًا عبر البريد الإلكتروني.
                    </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
                    {plans.map((plan) => (
                        <div
                            key={plan.name}
                            className={`rounded-2xl border p-6 shadow-lg transition-all hover:-translate-y-1 ${
                                plan.highlighted
                                    ? 'bg-eclipse-2 border-matcha ring-1 ring-matcha scale-[1.02]'
                                    : 'bg-eclipse-2 border-eclipse-3'
                            }`}
                        >
                            {/* رأس الكارد */}
                            <div className="mb-6">
                                <div className="flex items-center justify-between mb-3">
                                    <h3 className="text-2xl font-extrabold font-heading text-cream">{plan.name}</h3>
                                    {plan.badge ? (
                                        <span className="text-xs px-3 py-1 rounded-full bg-matcha/15 text-matcha border border-matcha/20">
                                            {plan.badge}
                                        </span>
                                    ) : null}
                                </div>
                                <div className="flex items-end gap-2">
                                    <span className="text-4xl font-extrabold text-cream">{plan.price}</span>
                                    <img src={RiyalIcon} alt="ريال سعودي" className="w-10 h-8 object-contain opacity-90" />
                                    <span className="text-cream-dim text-lg">{plan.period}</span>
                                </div>
                            </div>

                            {/* المميزات */}
                            <div className="space-y-3 mb-8">
                                {plan.features.map((feature) => (
                                    <div key={feature.text} className="flex items-start gap-3 text-sm">
                                        {feature.included
                                            ? <CheckIcon className="w-5 h-5 text-matcha mt-0.5 shrink-0" />
                                            : <XIcon className="w-5 h-5 text-red-400 mt-0.5 shrink-0" />
                                        }
                                        <span className={feature.included ? 'text-cream' : 'text-cream-dim'}>
                                            {feature.text}
                                        </span>
                                    </div>
                                ))}
                            </div>

                            {/* CTA — إيميل فقط، بدون زر */}
                            {plan.cta ? (
                                <a
                                    href={plan.cta}
                                    className="flex items-center justify-center gap-2 text-sm text-matcha hover:text-matcha-light transition-colors"
                                >
                                    <MailIcon className="w-4 h-4 shrink-0" />
                                    اشترك عبر البريد
                                </a>
                            ) : (
                                <div className="h-5" /> // مساحة فارغة للخطة المجانية
                            )}
                        </div>
                    ))}
                </div>

                {/* للشركات */}
                <div className="mt-10 rounded-2xl border border-eclipse-3 bg-eclipse-2 p-6">
                    <div className="flex items-start gap-4">
                        <div className="w-12 h-12 rounded-xl bg-matcha/10 flex items-center justify-center shrink-0">
                            <Building2Icon className="w-6 h-6 text-matcha" />
                        </div>
                        <div className="flex-1">
                            <h3 className="text-2xl font-bold text-cream mb-2">للشركات والمكاتب القانونية</h3>
                            <p className="text-cream-dim leading-7 mb-4">
                                عندكم عدد مستخدمين أكبر أو احتياج لحلول خاصة؟ نوفر ترتيبات مخصصة حسب حجم الاستخدام ونوع العقود.
                            </p>
                            <a
                                href={`mailto:${CONTACT_EMAIL}?subject=طلب باقة شركات - بصيرة`}
                                className="inline-flex items-center gap-2 text-sm text-matcha hover:text-matcha-light transition-colors"
                            >
                                <MailIcon className="w-4 h-4" />
                                {CONTACT_EMAIL}
                            </a>
                        </div>
                    </div>
                </div>

                <div className="mt-8 text-center text-sm text-cream-muted leading-7">
                    جميع الاشتراكات الحالية تتم عبر التواصل بالبريد الإلكتروني. المنصة تساعد في فهم العقود والكشف الأولي عن المخاطر، ولا تُعد بديلًا عن الاستشارة القانونية المتخصصة.
                </div>
            </div>
        </section>
    );
}
